import { workflow, node, trigger, expr } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'When clicking \'Test workflow\'' },
});

const denyTest = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'deny test',
    parameters: {
      mode: 'manual',
      includeOtherFields: false,
      fields: {
        values: [
          { name: 'result', type: 'stringValue', value: 'denied' },
        ],
      },
    },
  },
});

export default workflow('', 'deny test workflow')
  .add(manualTrigger)
  .to(denyTest);
